framework_css:
/*
  Dog Club Yearbook Portal - Global Framework Styles
  Matches Bootstrap-like admin style from reference design
*/

/* Typography imports */
@import url('https://fonts.googleapis.com/css2?family=Source+Sans+3:wght@300;400;500;600;700&family=Space+Grotesk:wght@500;700&family=Source+Code+Pro:wght@400;500&display=swap');

/* Design system tokens */
:root {
  /* Colors */
  --color-primary-dark: #222222;
  --color-primary-rust: #B86738;

  --color-secondary-gold: #F5D56A;
  --color-secondary-apricot: #F4C28A;

  --color-accent-blue: #337AB7;

  --color-neutral-0: #FFFFFF;
  --color-neutral-1: #F5F5F5;
  --color-neutral-2: #DDDDDD;
  --color-neutral-3: #333333;
  --color-neutral-4: #555555;

  --color-success: #5CB85C;
  --color-error: #D9534F;
  --color-warning: #F0AD4E;
  --color-info: #5BC0DE;

  /* Typography */
  --font-heading: Space Grotesk, Helvetica, sans-serif;
  --font-body: Source Sans 3, Arial, sans-serif;
  --font-code: Source Code Pro, monospace;

  --font-size-h1: 28px;
  --font-size-h2: 22px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --container-max-width: 1140px;
}

/* Global reset / base */
* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-3);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  height: auto;
  border: 0;
}

a {
  color: var(--color-accent-blue);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  margin-top: 0;
  margin-bottom: var(--space-2);
  color: var(--color-neutral-3);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

small {
  font-size: var(--font-size-small);
}

code {
  font-family: var(--font-code);
}

/* Layout helpers */
.container {
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

.site-main {
  padding-top: var(--space-4);
  padding-bottom: var(--space-6);
}

.page-container {
  /* Space below the hero band similar to design */
  margin-top: var(--space-3);
}

/* Top navigation bar */
.site-header {
  margin: 0;
}

.top-nav {
  background-color: var(--color-primary-dark);
  color: var(--color-neutral-0);
  font-family: var(--font-heading);
  font-size: var(--font-size-body);
}

.nav-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.brand {
  color: var(--color-secondary-gold);
  font-weight: var(--font-weight-semibold);
  white-space: nowrap;
}

.brand:hover,
.brand:focus {
  color: var(--color-secondary-gold);
  text-decoration: underline;
}

.nav-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
}

.nav-item {
  margin: 0;
}

.nav-link {
  color: var(--color-neutral-0);
  font-weight: var(--font-weight-regular);
  padding-top: var(--space-1);
  padding-bottom: var(--space-1);
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-secondary-gold);
  text-decoration: none;
}

.nav-link-active {
  color: var(--color-secondary-gold);
  font-weight: var(--font-weight-semibold);
}

/* Hero band below navigation */
.hero-band {
  background-color: var(--color-primary-rust);
  color: var(--color-neutral-0);
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
}

.hero-inner {
  display: flex;
  align-items: center;
}

.hero-logo {
  flex: 0 0 auto;
  margin-right: var(--space-4);
}

.hero-logo-image {
  max-width: 140px;
  border-radius: 50%;
  background-color: var(--color-neutral-0);
  border: 4px solid var(--color-neutral-0);
}

.hero-copy {
  flex: 1 1 auto;
}

.hero-title {
  color: var(--color-neutral-0);
  margin-bottom: var(--space-2);
}

.hero-subtitle {
  color: var(--color-neutral-0);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  margin: 0;
}

/* Buttons (for use in page-specific content) */
.btn {
  display: inline-block;
  padding: 8px 18px;
  font-size: var(--font-size-body);
  font-weight: var(--font-weight-medium);
  line-height: 1.42857143;
  text-align: center;
  white-space: nowrap;
  vertical-align: middle;
  border-radius: 4px;
  border: 1px solid var(--color-neutral-2);
  background-color: #F8F8F8;
  color: var(--color-neutral-3);
  cursor: pointer;
}

.btn:hover,
.btn:focus {
  background-color: var(--color-neutral-0);
  text-decoration: none;
}

.btn-primary {
  background-color: var(--color-accent-blue);
  border-color: #2e6da4;
  color: var(--color-neutral-0);
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #286090;
}

/* Footer */
.site-footer {
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
  background-color: var(--color-neutral-0);
}

.footer-inner {
  padding-top: var(--space-3);
  padding-bottom: var(--space-4);
}

.footer-separator {
  border: 0;
  border-top: 1px solid var(--color-neutral-2);
  margin-top: 0;
  margin-bottom: var(--space-3);
}

.footer-top {
  margin-bottom: var(--space-2);
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
}

.footer-nav a {
  color: var(--color-accent-blue);
}

.footer-nav a:hover,
.footer-nav a:focus {
  text-decoration: underline;
}

.footer-bottom {
  color: var(--color-neutral-4);
}

.footer-copy {
  margin: 0;
}

/* Simple responsiveness */
@media (max-width: 768px) {
  .nav-container {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-2);
  }

  .hero-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .hero-logo {
    margin-right: 0;
    margin-bottom: var(--space-3);
  }
}
